const config = $('Normalize Lazada Token Set').first().json;
const now = new Date();
const updateBefore = now.toISOString().slice(0, 19) + '+07:00';
const updateAfterDate = new Date(now.getTime() - Number(config.lookbackDays || '3') * 24 * 60 * 60 * 1000);
const updateAfter = updateAfterDate.toISOString().slice(0, 19) + '+07:00';
const pageSize = Math.max(1, Math.min(100, Number(config.pageSize || '100') || 100));
const maxPages = Math.max(1, Math.min(50, Number(config.maxPages || '20') || 20));
const pagePath = '/orders/get';

return Array.from({ length: maxPages }, (_, index) => {
  const offset = index * pageSize;
  const params = {
    access_token: config.accessToken,
    app_key: config.appKey,
    limit: String(pageSize),
    offset: String(offset),
    sign_method: 'sha256',
    sort_direction: 'DESC',
    timestamp: String(Date.now() + index),
    update_after: updateAfter,
    update_before: updateBefore
  };

  return {
    json: {
      ...config,
      pageSize,
      maxPages,
      offset,
      updateAfter,
      updateBefore,
      ordersRequestUrl: buildSignedUrl(config, pagePath, params)
    }
  };
});

