function toRecord(value) {
  return value && typeof value === 'object' && !Array.isArray(value) ? value : {};
}

function asArray(value) {
  return Array.isArray(value) ? value : [];
}

function asString(value) {
  return typeof value === 'string' && value.trim().length > 0 ? value.trim() : undefined;
}

function lower(value) {
  return typeof value === 'string' ? value.toLowerCase() : '';
}

function extractOrders(response) {
  const data = response.data || response.result?.data || response.result || response;
  if (Array.isArray(data?.orders)) return data.orders;
  if (Array.isArray(data?.order_list)) return data.order_list;
  if (Array.isArray(data)) return data;
  return [];
}

function normalizeLazadaOrderItems(response) {
  const data = response.data || response.result?.data || response.result || response;
  if (Array.isArray(data)) return data.map((item) => toRecord(item));

  const record = toRecord(data);
  const list = asArray(record.order_items || record.orderItems || record.items || record.list);
  return list.map((item) => toRecord(item));
}

function uniqueStrings(values) {
  return Array.from(new Set(values.filter((value) => typeof value === 'string' && value.length > 0)));
}

function pickBuyerName(order) {
  const shipping = order.address_shipping || order.shipping_address || {};
  const fromOrder = [order.customer_first_name, order.customer_last_name].filter(Boolean).join(' ').trim();
  const fromShipping = [shipping.first_name, shipping.last_name].filter(Boolean).join(' ').trim();
  return fromOrder || fromShipping || order.customer_name || order.buyer_name || null;
}

function collectStatuses(order) {
  return uniqueStrings([
    lower(order.status),
    lower(order.order_status),
    lower(order.orderStatus),
    lower(order.shipping_status),
    lower(order.shippingStatus),
    lower(order.fulfillment_status),
    lower(order.fulfillmentStatus)
  ]);
}

function isEligibleOrder(order) {
  const platformOrderId = String(order.order_id || order.orderId || '').trim();
  if (!platformOrderId) {
    return false;
  }

  const statuses = collectStatuses(order);
  if (statuses.length === 0) {
    return true;
  }

  const blockedTokens = ['cancel', 'unpaid', 'fail', 'return', 'delivered', 'closed'];
  return !statuses.some((status) => blockedTokens.some((token) => status.includes(token)));
}

function mapItem(item) {
  return {
    order_item_id: item.order_item_id ?? item.orderItemId ?? null,
    item_name: item.name ?? item.item_name ?? item.product_name ?? null,
    sku: item.sku ?? item.shop_sku ?? item.seller_sku ?? item.model_sku ?? null,
    quantity: item.quantity ?? item.qty ?? item.model_quantity_purchased ?? null,
    status: item.status ?? item.order_item_status ?? null,
    package_id: item.package_id ?? item.packageId ?? null,
    tracking_code: item.tracking_code ?? item.trackingCode ?? item.tracking_no ?? item.tracking_number ?? null,
    shipping_type: item.shipping_type ?? item.shippingType ?? null,
    delivery_option_sof: item.delivery_option_sof ?? null
  };
}

function pickBarcodeValue(order, items) {
  const trackingValues = uniqueStrings(
    items
      .map((item) => asString(item.tracking_code) || asString(item.trackingCode) || asString(item.tracking_no) || asString(item.tracking_number))
      .filter(Boolean)
  );

  if (trackingValues.length > 0) {
    return trackingValues[0];
  }

  const packageValues = uniqueStrings(
    items
      .map((item) => asString(item.package_id) || asString(item.packageId))
      .filter(Boolean)
  );

  if (packageValues.length > 0) {
    return packageValues[0];
  }

  return String(order.order_id || order.orderId || '').trim() || null;
}

async function fetchJson(url) {
  const response = await fetch(url);
  if (!response.ok) {
    throw new Error('Lazada request failed with status ' + response.status + ' for ' + url);
  }
  return response.json();
}

async function mapWithConcurrency(values, limit, iteratee) {
  const results = [];
  for (let index = 0; index < values.length; index += limit) {
    const chunk = values.slice(index, index + limit);
    const chunkResults = await Promise.all(chunk.map(iteratee));
    results.push(...chunkResults);
  }
  return results;
}

const config = $('Normalize Lazada Token Set').first().json;
const pageResponses = $input.all().map((item) => item.json);
const orders = [];

for (const response of pageResponses) {
  orders.push(...extractOrders(response));
}

const deduped = [];
const seen = new Set();
for (const order of orders) {
  const platformOrderId = String(order.order_id || order.orderId || '').trim();
  if (!platformOrderId || seen.has(platformOrderId)) {
    continue;
  }
  seen.add(platformOrderId);
  deduped.push(order);
}

const eligibleOrders = deduped.filter(isEligibleOrder);

const mappedOrders = await mapWithConcurrency(eligibleOrders, 5, async (order) => {
  const platformOrderId = String(order.order_id || order.orderId || '').trim();
  let items = [];

  try {
    const params = {
      access_token: config.accessToken,
      app_key: config.appKey,
      order_id: platformOrderId,
      sign_method: 'sha256',
      timestamp: String(Date.now())
    };
    const itemsUrl = buildSignedUrl(config, '/order/items/get', params);
    const itemsResponse = await fetchJson(itemsUrl);
    items = normalizeLazadaOrderItems(itemsResponse);
  } catch (error) {
    console.warn('Unable to load Lazada order items', platformOrderId, error instanceof Error ? error.message : error);
  }

  const body = {
    store_id: config.storeId,
    platform_order_id: platformOrderId,
    barcode_value: pickBarcodeValue(order, items),
    buyer_name: pickBuyerName(order),
    items_json: items.map(mapItem)
  };

  return {
    json: {
      ...body,
      supabaseUrl: config.supabaseUrl,
      serviceRoleKey: config.serviceRoleKey,
      requestUrl: config.supabaseUrl + '/rest/v1/orders?on_conflict=store_id,platform_order_id',
      requestBody: JSON.stringify(body)
    }
  };
});

return mappedOrders;

const inputItems = $input.all().map((item) => item.json);

if (inputItems.length === 0) {
  return [];
}

const config = $('Normalize Lazada Token Set').first().json;
const template = inputItems[0];
const batchSize = Math.max(
  1,
  Math.min(500, Number(template.supabaseBatchSize || config.supabaseBatchSize || '50') || 50)
);

const records = inputItems.map((item) => {
  if (typeof item.requestBody === 'string') {
    return JSON.parse(item.requestBody);
  }

  return {
    store_id: item.store_id,
    platform_order_id: item.platform_order_id,
    barcode_value: item.barcode_value,
    buyer_name: item.buyer_name,
    items_json: item.items_json
  };
});

const batches = [];
for (let index = 0; index < records.length; index += batchSize) {
  batches.push(records.slice(index, index + batchSize));
}

return batches.map((batch, index) => ({
  json: {
    ...template,
    requestBody: JSON.stringify(batch),
    batchIndex: index + 1,
    batchCount: batches.length,
    recordCount: batch.length,
    supabaseBatchSize: batchSize
  }
}));
